import { O9Button } from '../Button/Button';
import { O9IconButton } from '../IconButton/IconButton';
import { createIndicator, updateIndicator, removeIndicator, type IndicatorVariant, type IndicatorSize } from '@o9ds/utils';

export type FabButtonVariant = 'primary' | 'secondary';

export interface O9FabButtonOptions {
  variant?: FabButtonVariant;
  icon?: string;
  label?: string | null;
  isDisabled?: boolean;
  isLoading?: boolean;
  indicator?: IndicatorVariant | false;
  indicatorSize?: IndicatorSize;
  zIndex?: number | null;
  tooltip?: string;
  onClick?: (event: Event) => void;
  onFocus?: (event: FocusEvent) => void;
  onBlur?: (event: FocusEvent) => void;
}

type ResolvedOptions = {
  variant: FabButtonVariant;
  icon: string;
  label: string | null;
  isDisabled: boolean;
  isLoading: boolean;
  indicator: IndicatorVariant | false;
  indicatorSize: IndicatorSize;
  zIndex: number | null;
  tooltip: string | null;
  onClick: ((event: Event) => void) | null;
  onFocus: ((event: FocusEvent) => void) | null;
  onBlur: ((event: FocusEvent) => void) | null;
};

const VALID_VARIANTS: readonly FabButtonVariant[] = ['primary', 'secondary'];

export class O9FabButton {
  private _container: HTMLElement | null;
  private _wrapperEl: HTMLDivElement | null = null;
  private _buttonEl: HTMLButtonElement | null = null;
  private _innerButton: O9Button | O9IconButton | null = null;
  private _indicatorEl: HTMLSpanElement | null = null;
  private _options: ResolvedOptions;

  static readonly VARIANTS = VALID_VARIANTS;

  static readonly DEFAULTS: ResolvedOptions = {
    variant: 'primary',
    icon: 'plus',
    label: null,
    isDisabled: false,
    isLoading: false,
    indicator: false,
    indicatorSize: 'lg',
    zIndex: null,
    tooltip: null,
    onClick: null,
    onFocus: null,
    onBlur: null,
  };

  static initialize(element: HTMLElement, options?: O9FabButtonOptions): O9FabButton {
    return new O9FabButton(element, options);
  }

  constructor(element: HTMLElement, options?: O9FabButtonOptions) {
    this._container = element;

    const variant = options?.variant && VALID_VARIANTS.includes(options.variant)
      ? options.variant
      : O9FabButton.DEFAULTS.variant;

    this._options = {
      ...O9FabButton.DEFAULTS,
      ...options,
      variant,
      icon: options?.icon ?? O9FabButton.DEFAULTS.icon,
      label: options?.label ?? O9FabButton.DEFAULTS.label,
      tooltip: options?.tooltip ?? null,
      onClick: options?.onClick ?? null,
      onFocus: options?.onFocus ?? null,
      onBlur: options?.onBlur ?? null,
      zIndex: options?.zIndex ?? null,
    };

    this._render();
  }

  private _render(): void {
    if (!this._container) return;

    this._wrapperEl = document.createElement('div');
    this._applyWrapperClasses();
    this._applyZIndex();

    this._buttonEl = document.createElement('button');
    this._wrapperEl.appendChild(this._buttonEl);
    this._createInnerButton();

    if (this._options.indicator !== false && !this._options.isDisabled && !this._options.isLoading) {
      this._createIndicator();
    }

    this._container.appendChild(this._wrapperEl);
  }

  private _applyWrapperClasses(): void {
    if (!this._wrapperEl) return;

    const isWithLabel = this._options.label !== null;
    this._wrapperEl.className = [
      'o9ds-fab-btn',
      `o9ds-fab-btn--${this._options.variant}`,
      isWithLabel ? 'o9ds-fab-btn--with-label' : 'o9ds-fab-btn--icon-only',
      this._options.isDisabled ? 'is-disabled' : '',
      this._options.isLoading ? 'loading' : '',
    ]
      .filter(Boolean)
      .join(' ');
  }

  private _applyZIndex(): void {
    if (!this._wrapperEl) return;

    if (this._options.zIndex !== null) {
      this._wrapperEl.style.zIndex = String(this._options.zIndex);
    } else {
      this._wrapperEl.style.removeProperty('z-index');
    }
  }

  private _createInnerButton(): void {
    if (!this._buttonEl) return;

    if (this._options.label !== null) {
      this._innerButton = new O9Button(this._buttonEl, {
        variant: this._options.variant,
        size: 'md',
        icon: this._options.icon,
        label: this._options.label,
        isDisabled: this._options.isDisabled,
        isLoading: this._options.isLoading,
        tooltip: this._options.tooltip ?? undefined,
        onClick: this._options.onClick ?? undefined,
      });
    } else {
      this._innerButton = new O9IconButton(this._buttonEl, {
        variant: this._options.variant,
        size: 'lg',
        icon: this._options.icon,
        tooltip: this._options.tooltip ?? '',
        isDisabled: this._options.isDisabled,
        isLoading: this._options.isLoading,
        onClick: this._options.onClick ?? undefined,
      });
    }

    if (this._options.onFocus) {
      this._buttonEl.addEventListener('focus', this._options.onFocus as EventListener);
    }
    if (this._options.onBlur) {
      this._buttonEl.addEventListener('blur', this._options.onBlur as EventListener);
    }
  }

  private _destroyInnerButton(): void {
    if (this._buttonEl && this._options.onFocus) {
      this._buttonEl.removeEventListener('focus', this._options.onFocus as EventListener);
    }
    if (this._buttonEl && this._options.onBlur) {
      this._buttonEl.removeEventListener('blur', this._options.onBlur as EventListener);
    }

    this._innerButton?.destroy();
    this._innerButton = null;
  }

  private _createIndicator(): void {
    if (this._options.indicator === false || !this._wrapperEl) return;

    this._indicatorEl = createIndicator({
      variant: this._options.indicator,
      size: this._options.indicatorSize,
    });
    this._wrapperEl.appendChild(this._indicatorEl);
  }

  private _syncIndicatorVisibility(): void {
    const shouldShow = this._options.indicator !== false
      && !this._options.isDisabled
      && !this._options.isLoading;

    if (shouldShow && !this._indicatorEl) {
      this._createIndicator();
    } else if (!shouldShow && this._indicatorEl) {
      this._indicatorEl = removeIndicator(this._indicatorEl);
    }
  }

  setVariant(variant: string): void {
    if (!VALID_VARIANTS.includes(variant as FabButtonVariant)) return;

    this._options.variant = variant as FabButtonVariant;
    this._applyWrapperClasses();

    if (this._innerButton) {
      this._innerButton.setVariant(variant);
    }

    this._dispatchEvent('fab-btn:variant', { variant });
  }

  setIcon(iconName: string): void {
    this._options.icon = iconName;

    if (this._innerButton) {
      this._innerButton.setIcon(iconName);
    }
  }

  setLabel(label: string | null): void {
    const wasWithLabel = this._options.label !== null;
    const isWithLabel = label !== null;
    this._options.label = label;

    if (wasWithLabel !== isWithLabel) {
      this._destroyInnerButton();
      this._buttonEl?.remove();
      this._buttonEl = document.createElement('button');

      if (this._indicatorEl) {
        this._wrapperEl?.insertBefore(this._buttonEl, this._indicatorEl);
      } else {
        this._wrapperEl?.appendChild(this._buttonEl);
      }

      this._createInnerButton();
      this._applyWrapperClasses();
    } else if (isWithLabel && this._innerButton instanceof O9Button) {
      this._innerButton.setLabel(label!);
    }
  }

  setIndicator(variant: IndicatorVariant | false): void {
    this._options.indicator = variant;

    if (variant === false) {
      this._indicatorEl = removeIndicator(this._indicatorEl);
      return;
    }

    if (this._options.isDisabled || this._options.isLoading) return;

    if (this._indicatorEl) {
      updateIndicator(this._indicatorEl, { variant });
    } else {
      this._createIndicator();
    }
  }

  setIndicatorSize(size: IndicatorSize): void {
    this._options.indicatorSize = size;

    if (this._indicatorEl) {
      updateIndicator(this._indicatorEl, { size });
    }
  }

  setZIndex(zIndex: number | null): void {
    this._options.zIndex = zIndex;
    this._applyZIndex();
  }

  disabled(state?: boolean): boolean | void {
    if (state === undefined) {
      return this._options.isDisabled;
    }

    this._options.isDisabled = state;
    this._applyWrapperClasses();

    if (this._innerButton) {
      this._innerButton.disabled(state);
    }

    this._syncIndicatorVisibility();
  }

  setLoading(isLoading: boolean): void {
    this._options.isLoading = isLoading;
    this._applyWrapperClasses();

    if (this._innerButton) {
      this._innerButton.setLoading(isLoading);
    }

    if (this._wrapperEl) {
      if (isLoading) {
        this._wrapperEl.setAttribute('aria-busy', 'true');
      } else {
        this._wrapperEl.removeAttribute('aria-busy');
      }
    }

    this._syncIndicatorVisibility();
  }

  focus(): void {
    if (this._buttonEl && !this._options.isLoading) {
      this._buttonEl.focus();
    }
  }

  destroy(): void {
    this._destroyInnerButton();
    this._indicatorEl = removeIndicator(this._indicatorEl);

    this._buttonEl?.remove();
    this._buttonEl = null;

    this._wrapperEl?.remove();
    this._wrapperEl = null;

    this._container = null;
  }

  private _dispatchEvent(name: string, detail: Record<string, unknown>): void {
    this._wrapperEl?.dispatchEvent(new CustomEvent(name, {
      bubbles: true,
      cancelable: true,
      detail,
    }));
  }
}
